import re
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt

with open('/app/text.gcode', 'r') as f:
    lines = f.readlines()

current_object = -1
x, y, z = 0.0, 0.0, 0.0
extruding_segments = []

for line in lines:
    line = line.strip()

    if line.startswith('M486 S'):
        val = line.split('S')[1].strip()
        try:
            current_object = int(val)
        except:
            pass
        continue

    if current_object != 0:
        continue

    m = re.match(r'G[01]\s', line)
    if not m:
        continue

    new_x, new_y, new_z = x, y, z
    has_e = False
    e_val = 0

    for part in line.split():
        if part.startswith('X'):
            try: new_x = float(part[1:])
            except: pass
        elif part.startswith('Y'):
            try: new_y = float(part[1:])
            except: pass
        elif part.startswith('Z'):
            try: new_z = float(part[1:])
            except: pass
        elif part.startswith('E'):
            try:
                e_val = float(part[1:])
                has_e = True
            except: pass

    if has_e and e_val > 0:
        extruding_segments.append((x, y, new_x, new_y, new_z))

    x, y, z = new_x, new_y, new_z

best_z = 11.12
layer_segments = [s for s in extruding_segments if abs(s[4] - best_z) < 0.01]

fig, ax = plt.subplots(1, 1, figsize=(20, 8))
for seg in layer_segments:
    ax.plot([seg[0], seg[2]], [seg[1], seg[3]], 'k-', linewidth=0.8)
ax.set_aspect('equal')
ax.set_title(f'Embossed Text - Layer Z={best_z:.2f}')
plt.tight_layout()
plt.savefig('/app/text_clear.png', dpi=150)
print("Saved text_clear.png")

